    ],
  };

  const helpMenu: MenuItemConstructorOptions = {
    label: t("help.name"),
    submenu: [
      {
        label: t("help.learnMore"),
        click: () => {
          void openAppOrigin();
        },
      },
    ],
  };

  const template: MenuItemConstructorOptions[] = [
    ...(isMac ? [appMenu] : []),
    fileMenu,
    editMenu,
    viewMenu,
    windowMenu,
    helpMenu,
  ];

  return Menu.buildFromTemplate(template);
}

