/* Settings window */

.settings-window__inner {
  display: flex;
  flex-direction: column;
  height: 100vh;
  background: transparent;
}

.settings-toolbar {
  -webkit-app-region: drag;
  display: flex;
  gap: calc(var(--spacing) * 1);
  justify-content: center;
  align-items: flex-end;
  padding: 36px calc(var(--spacing) * 4) calc(var(--spacing) * 2);
  border-bottom: 1px solid var(--color-border);
}

.settings-toolbar__tab {
  -webkit-app-region: no-drag;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  min-width: 72px;
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 2);
  font: inherit;
  font-size: var(--text-sm);
  color: var(--color-text-foreground-tertiary);
  appearance: none;
  cursor: default;
  background: transparent;
  border: 0;
  border-radius: 6px;
}

.settings-toolbar__tab:hover {
  color: var(--color-text-foreground-secondary);
  background: var(--color-background-button-tertiary-hover);
}

.settings-toolbar__tab.active {
  color: var(--color-text-foreground);
  background: var(--color-background-button-tertiary-active);
}

.settings-toolbar__icon {
  width: 20px;
  height: 20px;
}

.settings-toolbar__label {
  font-size: var(--text-sm);
}

.settings-pane {
  flex: 1;
  min-height: 0;
  padding: calc(var(--spacing) * 5) calc(var(--spacing) * 6);
  overflow-y: auto;
}

.settings-pane .settings-section {
  max-width: none;
  margin: 0 0 calc(var(--spacing) * 4);
}

/* Account pane */

.account-identity {
  display: flex;
  gap: calc(var(--spacing) * 3);
  align-items: center;
}

.account-avatar {
  width: 40px;
  height: 40px;
  object-fit: cover;
  background: var(--color-background-elevated-secondary);
  border-radius: 50%;
}

.account-avatar--placeholder {
  background: var(--color-background-elevated-primary-opaque);
}

.account-name {
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-text-foreground);
}

.account-email {
  font-size: var(--text-sm);
  color: var(--color-text-foreground-tertiary);
}

.settings-button {
  -webkit-app-region: no-drag;
  display: inline-flex;
  gap: calc(var(--spacing) * 1.5);
  align-items: center;
  padding: calc(var(--spacing) * 1) calc(var(--spacing) * 2.5);
  font: inherit;
  font-size: var(--text-sm);
  color: var(--color-text-foreground);
  appearance: none;
  cursor: default;
  background: var(--color-background-elevated-secondary);
  border: 1px solid var(--color-border);
  border-radius: 6px;
}

.settings-button--destructive {
  color: #ef4444;
}

.settings-button--destructive:hover {
  background: rgba(239, 68, 68, 0.08);
}

