import { Settings as Gear, Keyboard, Palette, User } from "lucide-react";
import { useState } from "react";
import type { FormatPlatform } from "../../../../shared/accelerators";
import { Account } from "./panes/account";
import { Appearance } from "./panes/appearance";
import { General } from "./panes/general";
import { Shortcuts } from "./panes/shortcuts";

type PaneId = "account" | "general" | "appearance" | "shortcuts";

const TABS: Array<{ id: PaneId; label: string; Icon: typeof User }> = [
  { id: "account", label: "Account", Icon: User },
  { id: "general", label: "General", Icon: Gear },
  { id: "appearance", label: "Appearance", Icon: Palette },
  { id: "shortcuts", label: "Shortcuts", Icon: Keyboard },
];

export function SettingsWindow({ platform }: { platform: FormatPlatform }) {
  const [pane, setPane] = useState<PaneId>("account");
  return (
    <div className="settings-window__inner">
      <nav className="settings-toolbar" role="tablist">
        {TABS.map(({ id, label, Icon }) => (
          <button
            aria-selected={pane === id}
            className={`settings-toolbar__tab${pane === id ? " active" : ""}`}
            key={id}
            onClick={() => setPane(id)}
            role="tab"
            type="button"
          >
            <Icon aria-hidden className="settings-toolbar__icon" size={20} />
            <span className="settings-toolbar__label">{label}</span>
          </button>
        ))}
      </nav>
      <div className="settings-pane" role="tabpanel">
        {pane === "account" && <Account />}
        {pane === "general" && <General />}
        {pane === "appearance" && <Appearance />}
        {pane === "shortcuts" && <Shortcuts platform={platform} />}
      </div>
    </div>
  );
}

import { DesktopTRPCProvider } from "@repo/app-trpc/desktop";
import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import type { FormatPlatform } from "../../../shared/accelerators";
import { AppShell } from "./app-shell";
import { SettingsWindow } from "./settings/SettingsWindow";
import { UserMenu } from "./user-menu";

const appOrigin = window.lightfastBridge.appOrigin;
const platform = window.lightfastBridge.platform;
const formatPlatform: FormatPlatform =
  platform === "darwin" || platform === "linux" || platform === "win32"
    ? platform
    : "linux";

function Providers({ children }: { children: React.ReactNode }) {
  return (
    <StrictMode>
      <DesktopTRPCProvider baseUrl={appOrigin}>{children}</DesktopTRPCProvider>
    </StrictMode>
  );
}

if (window.codexWindowType === "settings") {
  const settingsContainer = document.getElementById("settings-root");
  if (settingsContainer) {
    createRoot(settingsContainer).render(
      <Providers>
        <SettingsWindow platform={formatPlatform} />
      </Providers>
    );
  }
} else {
  const container = document.getElementById("react-root");
  if (container) {
    createRoot(container).render(
      <Providers>
        <AppShell />
      </Providers>
    );
  }

  const userMenuContainer = document.getElementById("user-menu-root");
  if (userMenuContainer) {
    createRoot(userMenuContainer).render(
      <Providers>
        <UserMenu />
      </Providers>
    );
  }
}

