import type { ThemeSource } from "../../../../../shared/ipc";
import { useSettingsSnapshot } from "../use-settings-snapshot";

const THEME_OPTIONS: Array<{ value: ThemeSource; label: string }> = [
  { value: "system", label: "System" },
  { value: "light", label: "Light" },
  { value: "dark", label: "Dark" },
];

export function Appearance() {
  const snapshot = useSettingsSnapshot();
  return (
    <section className="settings-section">
      <div className="settings-card">
        <div className="settings-row">
          <div className="settings-row__label">Theme</div>
          <div className="segmented">
            {THEME_OPTIONS.map((option) => (
              <button
                className={
                  snapshot.themeSource === option.value
                    ? "segmented__button active"
                    : "segmented__button"
                }
                key={option.value}
                onClick={() =>
                  void window.lightfastBridge.updateSetting(
                    "themeSource",
                    option.value
                  )
                }
                type="button"
              >
                {option.label}
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

import { useTRPC } from "@repo/app-trpc/react";
import { useQuery } from "@tanstack/react-query";
import { LogOut } from "lucide-react";

export function Account() {
  const trpc = useTRPC();
  const query = useQuery(trpc.account.get.queryOptions());
  const data = query.data;

  return (
    <section className="settings-section">
      <div className="settings-card">
        <div className="settings-row">
          <div className="account-identity">
            <div
              aria-hidden
              className={
                data?.imageUrl
                  ? "account-avatar"
                  : "account-avatar account-avatar--placeholder"
              }
              style={
                data?.imageUrl
                  ? { backgroundImage: `url("${data.imageUrl}")` }
                  : undefined
              }
            />
            <div>
              <div className="account-name">{data?.fullName ?? "—"}</div>
              <div className="account-email">
                {data?.primaryEmailAddress ?? ""}
              </div>
            </div>
          </div>
        </div>
      </div>
      <div className="settings-card">
        <div className="settings-row">
          <div className="settings-row__label">Sign out of Lightfast</div>
          <button
            className="settings-button settings-button--destructive"
            onClick={() => void window.lightfastBridge.auth.signOut()}
            type="button"
          >
            <LogOut size={14} />
            <span>Sign out</span>
          </button>
        </div>
      </div>
    </section>
  );
}

import { DesktopTRPCProvider } from "@repo/app-trpc/desktop";
import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import type { FormatPlatform } from "../../../shared/accelerators";
import { AppShell } from "./app-shell";
import { SettingsWindow } from "./settings/settings-window";
import { UserMenu } from "./user-menu";

const appOrigin = window.lightfastBridge.appOrigin;
const platform = window.lightfastBridge.platform;
const formatPlatform: FormatPlatform =
  platform === "darwin" || platform === "linux" || platform === "win32"
    ? platform
    : "linux";

function Providers({ children }: { children: React.ReactNode }) {
  return (
    <StrictMode>
      <DesktopTRPCProvider baseUrl={appOrigin}>{children}</DesktopTRPCProvider>
    </StrictMode>
  );
}

if (window.codexWindowType === "settings") {
  const settingsContainer = document.getElementById("settings-root");
  if (settingsContainer) {
    createRoot(settingsContainer).render(
      <Providers>
        <SettingsWindow platform={formatPlatform} />
      </Providers>
    );
  }
} else {
  const container = document.getElementById("react-root");
  if (container) {
    createRoot(container).render(
      <Providers>
        <AppShell />
      </Providers>
    );
  }

  const userMenuContainer = document.getElementById("user-menu-root");
  if (userMenuContainer) {
    createRoot(userMenuContainer).render(
      <Providers>
        <UserMenu />
      </Providers>
    );
  }
}

